#include <iostream>
#include <string>
#include <sstream>

// This driver redirects std::cin and std::cout to test the main function
// of the user's program. It assumes the user's program has a 'main' function
// that reads an integer from std::cin and prints the reversed number to std::cout.

std::string run_test(const std::string& input_str) {
    std::istringstream iss(input_str);
    std::ostringstream oss;

    // Save original streambufs
    std::streambuf* old_cin = std::cin.rdbuf(iss.rdbuf());
    std::streambuf* old_cout = std::cout.rdbuf(oss.rdbuf());

    // Call the main function of the student's program
    // This will execute the program as if it were run interactively
    main(); 

    // Restore original streambufs
    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);

    return oss.str();
}
